import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"90A. Safe Rostering And Fatigue","description":"","frontmatter":{"title":"90A. Safe Rostering And Fatigue","eba":"Allied Health Professionals 2021-2026","topics":["hours","rosters","preliminary"]},"headers":[],"relativePath":"ebas/allied-health/classification-staffing/90A-safe-rostering-and-fatigue.md","filePath":"ebas/allied-health/classification-staffing/90A-safe-rostering-and-fatigue.md"}'),r={name:"ebas/allied-health/classification-staffing/90A-safe-rostering-and-fatigue.md"};function i(o,e,l,c,g,f){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_90a-safe-rostering-and-fatigue" tabindex="-1">90A. Safe Rostering And Fatigue <a class="header-anchor" href="#_90a-safe-rostering-and-fatigue" aria-label="Permalink to &quot;90A. Safe Rostering And Fatigue&quot;">​</a></h1><p><strong>90A.1</strong> Safe rostering practices It is recognised that rostering arrangements have an impact on safe staffing. In setting a roster, the Employer and, in the case of self-rostering (however</p><p>described), Employees will ensure that the number of changes to the Employee’s start and finish times are reasonable taking into account:</p><p><strong>(a)</strong> the Employee’s health and safety;</p><p><strong>(b)</strong> the Employee’s personal circumstances, including family responsibilities;</p><p><strong>(c)</strong> the number of changes to the Employee’s starting and finishing times in the preceding week and month;</p><p><strong>(d)</strong> the time difference between the different starting and finishing times, from shift to shift and in the preceding week and month; and</p><p><strong>(e)</strong> the break between shifts.</p><p><strong>90A.2</strong> Occupational Health and Safety The Employer will take into account occupational health and safety, having regard to the WorkSafe Victoria - Work-related Fatigue: A Guide for Employers when allocating work and when concerns about rostering practices are raised.</p><p><strong>90A.3</strong> Safety and Leave The Employer recognises the benefits of ensuring that Employees balance their professional and personal lives and are committed to ensuring this occurs. This includes that Employees receive annual leave as required by <a href="/eba/ebas/allied-health/leave/59-annual-leave.html">clause 59</a> (Annual leave). Specifically, <a href="/eba/ebas/allied-health/leave/59-annual-leave.html">clause 59</a> prescribes:</p><p><strong>(a)</strong> that an Employer must not unreasonably refuse requests for annual leave (see subclause 59.3(b)); and</p><p><strong>(b)</strong> a procedure for handling excessive annual leave accruals (see subclause 59.7).</p>',12)])])}const p=a(r,[["render",i]]);export{d as __pageData,p as default};
